Rule.Source:
      
    import java.util.ArrayList;
    import java.util.Arrays;
    import java.util.Iterator;
    import java.util.List;

    import sailpoint.api.SailPointContext;
    import sailpoint.object.Filter;
    import sailpoint.object.Identity;
    import sailpoint.object.IdentityEntitlement;
    import sailpoint.object.QueryOptions;
  	import sailpoint.object.Custom;
    
    import org.ascn.utils.Common;
    
    String RULE_NAME = "ASCN-AcrobatPro-Attestation-EntitySelector";
    String LOG_NAME = "sailpoint.ascension.AcrobatPro.entityselector";
    Common.info(LOG_NAME,"Entering " + RULE_NAME);
    
    List names = new ArrayList();
    QueryOptions qo = new QueryOptions();
    String appName = "AD-DS";

  	Custom ASEnt = context.getObjectByName(Custom.class,"ASCN-AcrobatPro-entitlements");
  	  
  try{
  	if(ASEnt != null)
    {
			entitlementsToCertify=(ArrayList)ASEnt.get("Entitlements");
    }
  	
  		Filter filter =   Filter.ignoreCase(Filter.and(Filter.eq("application.name", appName),Filter.in("value",entitlementsToCertify),Filter.eq("name", "memberOf")));
        qo.addFilter(filter);
        Iterator identityEntNames = context.search(IdentityEntitlement.class, qo);
  
  			while (identityEntNames.hasNext()) 
        {
            IdentityEntitlement  ie = (IdentityEntitlement) identityEntNames.next();
            String identityName = ie.getIdentity().getName();  
            if (identityName != null) 
            {   
                names.add(identityName);
            }
        }
    }
  	catch(Exception e)
    {
        Common.error(LOG_NAME,"Error in AcrobatPro Entity Selector Rule"+e);
    }
    Common.info(LOG_NAME,"Exiting " + RULE_NAME);
    return names;
